namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Title { get; set; }
    public required string Description { get; set; }
    public int Credits { get; set; }
    public required string Schedule { get; set; }
    public required string InstructorName { get; set; }
    public required string InstructorBio { get; set; }
    public required string DepartmentCode { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public required string Code { get; set; }
    public required string Name { get; set; }
    public required string Description { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    IReadOnlyList<Department> GetDepartments();
    Department? GetDepartment(string code);
    IReadOnlyList<Course> GetCourses(string? departmentCode = null, string? searchTerm = null);
    IReadOnlyList<Course> GetFeaturedCourses();
    Course? GetCourse(int id);
    void SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
        new() { Code = "ENG", Name = "English", Description = "Literature, writing, and language studies." },
        new() { Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Code = "HIST", Name = "History", Description = "Exploration of past events, cultures, and civilizations." },
    ];

    private static readonly List<Course> Courses =
    [
        new() { Id = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Covers variables, control flow, functions, and object-oriented basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT.", DepartmentCode = "CS", IsFeatured = true },
        new() { Id = 2, Code = "CS201", Title = "Data Structures & Algorithms", Description = "Study fundamental data structures (arrays, trees, graphs, hash tables) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published over 40 papers in top CS conferences.", DepartmentCode = "CS", IsFeatured = true },
        new() { Id = 3, Code = "CS301", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transactions, and an introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Maria Garcia", InstructorBio = "Prof. Garcia worked as a database architect at Oracle for a decade before joining academia.", DepartmentCode = "CS", IsFeatured = false },
        new() { Id = 4, Code = "CS401", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, and practical applications of AI.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Alan Turing Jr.", InstructorBio = "Dr. Turing is a leading researcher in deep learning with multiple industry collaborations.", DepartmentCode = "CS", IsFeatured = true },
        new() { Id = 5, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson is an award-winning educator specializing in making calculus accessible to all students.", DepartmentCode = "MATH", IsFeatured = true },
        new() { Id = 6, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Robert Lin", InstructorBio = "Dr. Lin's research spans numerical linear algebra and scientific computing.", DepartmentCode = "MATH", IsFeatured = false },
        new() { Id = 7, Code = "MATH301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Priya Patel", InstructorBio = "Dr. Patel has consulted for major pharmaceutical companies on biostatistics.", DepartmentCode = "MATH", IsFeatured = false },
        new() { Id = 8, Code = "ENG101", Title = "Composition & Rhetoric", Description = "Develop clear, persuasive writing skills through essay composition and rhetorical analysis.", Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", InstructorName = "Prof. David Brooks", InstructorBio = "Prof. Brooks is a published author and former journalist with the New York Times.", DepartmentCode = "ENG", IsFeatured = false },
        new() { Id = 9, Code = "ENG205", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present day.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Angela Morrison", InstructorBio = "Dr. Morrison specializes in 20th-century American fiction and has written three critical studies.", DepartmentCode = "ENG", IsFeatured = true },
        new() { Id = 10, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Richard Feynman II", InstructorBio = "Dr. Feynman is known for innovative physics demonstrations and student-centered teaching.", DepartmentCode = "PHYS", IsFeatured = false },
        new() { Id = 11, Code = "PHYS201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM + Fri Lab 1:00–3:50 PM", InstructorName = "Dr. Nikola Petrovic", InstructorBio = "Dr. Petrovic holds patents in electromagnetic sensor design and has 20 years of teaching experience.", DepartmentCode = "PHYS", IsFeatured = false },
        new() { Id = 12, Code = "HIST101", Title = "World Civilizations", Description = "Survey of major world civilizations from antiquity to the early modern period.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Helen Zhang", InstructorBio = "Dr. Zhang is an archaeologist and historian who has led excavations across three continents.", DepartmentCode = "HIST", IsFeatured = true },
        new() { Id = 13, Code = "HIST301", Title = "Modern European History", Description = "European history from the French Revolution to the present, covering political, social, and cultural transformations.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Prof. Thomas Müller", InstructorBio = "Prof. Müller is a specialist in 19th-century European political history with extensive archival research.", DepartmentCode = "HIST", IsFeatured = false },
    ];

    public IReadOnlyList<Department> GetDepartments() => Departments;

    public Department? GetDepartment(string code) =>
        Departments.FirstOrDefault(d => d.Code.Equals(code, StringComparison.OrdinalIgnoreCase));

    public IReadOnlyList<Course> GetCourses(string? departmentCode = null, string? searchTerm = null)
    {
        var query = Courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentCode))
        {
            query = query.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        Courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) =>
        Courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist to a database.
        // For now, we just validate and accept the request.
    }
}

