arguments.file_text:
@page "/"
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Explore our departments and courses for the upcoming semester.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code — @course.Title</h5>
                    <p class="card-text text-muted">@course.Credits credits · @course.DepartmentCode</p>
                    <p class="card-text">@Truncate(course.Description, 100)</p>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?department=@dept.Code" class="btn btn-outline-primary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private IReadOnlyList<Models.Course> featuredCourses = [];
    private IReadOnlyList<Models.Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject ICatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartment">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Code">@dept.Name</option>
            }
        </select>
    </div>
</div>

@{
    var filtered = CatalogService.GetCourses(selectedDepartment, searchTerm);
}

@if (filtered.Count == 0)
{
    <p class="text-muted">No courses found matching your criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
