@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject ICatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartment">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Code">@dept.Name</option>
            }
        </select>
    </div>
</div>

@{
    var filtered = CatalogService.GetCourses(selectedDepartment, searchTerm);
}

@if (filtered.Count == 0)
{
    <p class="text-muted">No courses found matching your criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in filtered)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentCode</td>
                    <td>@course.Credits</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string searchTerm = string.Empty;
    private string selectedDepartment = string.Empty;
    private IReadOnlyList<Department> departments = [];

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();

        var uri = new Uri(Navigation.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        var dept = query["department"];
        if (!string.IsNullOrEmpty(dept))
        {
            selectedDepartment = dept;
        }
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h3>Description</h3>
            <p>@course.Description</p>

            <h3>Schedule</h3>
            <p><strong>@course.Schedule</strong></p>

            <h3>Credits</h3>
            <p><span class="badge bg-primary fs-6">@course.Credits credits</span></p>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header">
                    <h5 class="mb-0">Instructor</h5>
                </div>
                <div class="card-body">
                    <h6>@course.InstructorName</h6>
                    <p class="text-muted">@course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit a request to enroll in a course. All fields are required.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@model.Name</strong>. Your enrollment request for
            <strong>@selectedCourseTitle</strong> has been received. You will be notified of your enrollment status.</p>
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="name" class="form-label">Full Name</label>
            <InputText id="name" class="form-control" @bind-Value="model.Name" />
            <ValidationMessage For="() => model.Name" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" />
            <ValidationMessage For="() => model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                <option value="0">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery]
    private int? courseId { get; set; }

    private IReadOnlyList<Course> courses = [];
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (courseId.HasValue && model.CourseId == 0)
        {
            model.CourseId = courseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(model);
        var course = CatalogService.GetCourse(model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown Course";
        submitted = true;
    }
}

